#include<bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=20;
int f[1<<maxn][maxn],a[maxn][maxn],n,ans=1e9;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=0;i<n;i++){
		for(int j=0;j<n;j++){
			cin>>a[i][j];
		}
	}
	fill(f[1]+1,f[1<<n],1e9);
	for(int i=1;i<1<<n;i++){
		for(int j=0;j<n;j++){
			for(int k=0;k<n;k++){
				if(!(i>>k&1)){
					f[i|1<<k][k]=min(f[i][j]+a[j][k],f[i|1<<k][k]);
				}
			}
		}
	}
	for(int j=0;j<n;j++){
		ans=min(ans,f[(1<<n)-1][j]+a[j][0]);
	}
	cout<<ans;
	return 0;
}
